from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['content_management']
users_collection = db['users']
documents_collection = db['documents']

# User profile storage
@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.json
    users_collection.insert_one(user_data)
    return jsonify({'message': 'User created successfully'}), 201

# Document queries
@app.route('/documents/<category>', methods=['GET'])
def get_documents(category):
    documents = documents_collection.find({'category': category})
    return jsonify(list(documents)), 200

# Aggregation pipelines
@app.route('/statistics', methods=['GET'])
def get_statistics():
    pipeline = [
        {'$match': {}},
        {'$group': {'_id': '$category', 'count': {'$sum': 1}}},
        {'$sort': {'count': -1}}
    ]
    statistics = list(documents_collection.aggregate(pipeline))
    return jsonify(statistics), 200

if __name__ == '__main__':
    app.run(debug=True)